$tableIds = @('3290a0b1-97cc-80c8-a64f-d3d8e47793c1','3290a0b1-97cc-809a-b9aa-e84d03b4c898','3290a0b1-97cc-805a-ae65-f2f0f9981c2b','3290a0b1-97cc-80f4-98f8-cd4e17258a55','3290a0b1-97cc-8072-8070-f11555f9db23')
foreach($id in $tableIds){
  Write-Output "TABLE $id"
  $r = Invoke-RestMethod -Method Get -Uri "https://api.notion.com/v1/blocks/$id/children?page_size=100" -Headers $headers
  foreach($row in $r.results){
    if($row.type -eq 'table_row'){
      $cells = @()
      foreach($cell in $row.table_row.cells){ $cells += (($cell.plain_text) -join '') }
      Write-Output ($cells -join ' | ')
    } else {
      Write-Output ("ROWTYPE " + $row.type)
    }
  }
  Write-Output "---"
}

